	@Test
	void minusMembershipPreservesUndefCompatibilityAndOuterBags() throws Exception {
		System.setProperty(MEMBERSHIP_THRESHOLD, "64");
		long[][] blocked = new long[65][4];
		for (int i = 0; i < blocked.length; i++) {
			blocked[i] = new long[] { 100L + i, PREDICATE, OBJECT, NULL_CONTEXT_ID };
		}
		TrackingMembershipSource source = new TrackingMembershipSource(blocked);
		RowState row = row(source, 1);
		long[] outerKeys = new long[69];
		for (int i = 0; i < 65; i++) {
			outerKeys[i] = 100L + i;
		}
		outerKeys[65] = UNKNOWN;
		outerKeys[66] = UNKNOWN;
		outerKeys[67] = 999L;
		outerKeys[68] = 999L;
		PatternPlan right = new PatternPlan(Term.slot(0), Term.constant(PREDICATE), Term.constant(OBJECT),
				Term.constant(NULL_CONTEXT_ID), ContextConstraint.UNRESTRICTED, false, blocked.length);
		MinusCursor cursor = new MinusCursor(new KeySequenceCursor(row, outerKeys), right, 1L, row);
		List<Long> emitted = new ArrayList<>();

		try (cursor) {
			while (cursor.next()) {
				emitted.add(row.slots[0]);
			}
		}

		assertThat(emitted).containsExactly(UNKNOWN, UNKNOWN, 999L, 999L);
		assertThat(source.sweepOpens).isOne();
		assertThat(source.directHasCalls).isEqualTo(64);
	}

	private static void prime(PatternMembershipProbe probe, RowState row, TrackingMembershipSource source,
			long[][] records, int count, boolean namedOnly, ContextConstraint contexts) {
		for (int i = 0; i < count; i++) {
			setKey(row, records[i][0]);
			int result = probe.test(row);
			if (result == PatternMembershipProbe.NOT_APPLICABLE) {
				boolean matched = (!namedOnly || records[i][3] != NULL_CONTEXT_ID)
						&& (contexts == null || contexts.contains(records[i][3]));
				probe.recordDirectResult(matched && source.has(records[i][0], PREDICATE, OBJECT, records[i][3]));
			}
		}
	}

	private static RowState row(TrackingMembershipSource source, int width) {
		Map<String, Integer> slots = new LinkedHashMap<>();
		for (int i = 0; i < width; i++) {
			slots.put("k" + i, i);
		}
		NativeSlotLayout layout = new NativeSlotLayout(slots, null);
		layout.freeze(new ArrayList<>(slots.keySet()));
		RowState row = new RowState(source, layout, EmptyBindingSet.getInstance());
		Arrays.fill(row.slots, UNKNOWN);
		row.recomputeBoundMask();
		return row;
	}

	private static void setKey(RowState row, long key) {
		row.slots[0] = key;
		row.recomputeBoundMask();
	}

	private static void copyKey(RowState row, long[] record, int width) {
		for (int i = 0; i < width; i++) {
			row.slots[i] = record[i];
		}
		row.recomputeBoundMask();
	}

	private static Term[] tupleTerms(int width) {
		return new Term[] {
				Term.slot(0),
				width >= 2 ? Term.slot(1) : Term.constant(PREDICATE),
				width >= 3 ? Term.slot(2) : Term.constant(OBJECT),
				width >= 4 ? Term.slot(3) : Term.constant(NAMED_CONTEXT)
		};
	}

	private static long[][] tupleRecords(int width, int count) {
		long[][] records = new long[count][4];
		for (int i = 0; i < count; i++) {
			records[i] = new long[] {
					100L + i,
					width >= 2 ? 1_000L + i : PREDICATE,
					width >= 3 ? 2_000L + i : OBJECT,
					width >= 4 ? 3_000L + i : NAMED_CONTEXT
			};
		}
		return records;
	}

	private static final class KeySequenceCursor implements RowCursor {
		private final RowState row;
		private final long[] keys;
		private int index;

		private KeySequenceCursor(RowState row, long[] keys) {
			this.row = row;
			this.keys = keys;
		}

		@Override
		public boolean next() {
			if (index == keys.length) {
				return false;
			}
			setKey(row, keys[index++]);
			return true;
		}

		@Override
		public void close() {
			index = keys.length;
		}
	}

	private static final class TrackingMembershipSource implements NativeLmdbQuerySource {
		private final long[][] records;
		private final List<Long> requestedContexts = new ArrayList<>();
		private int sweepOpens;
		private int directHasCalls;

		private TrackingMembershipSource(long[][] records) {
			this.records = records;
		}

		@Override
		public long idOf(Value value) {
			return UNKNOWN_ID;
		}

		@Override
		public Value lazyValue(long id) {
			throw new UnsupportedOperationException();
		}

		@Override
		public Object idSpace() {
			return this;
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) {
			sweepOpens++;
			requestedContexts.add(context);
			return new RecordIterator() {
				private int index;

				@Override
				public long[] next() {
					while (index < records.length) {
						long[] candidate = records[index++];
						if (matches(subj, candidate[0]) && matches(pred, candidate[1])
								&& matches(obj, candidate[2]) && matches(context, candidate[3])) {
							return candidate;
						}
					}
					return null;
				}

				@Override
				public void close() {
					index = records.length;
				}
			};
		}

		@Override
		public long count(long subj, long pred, long obj, long context) {
			long count = 0L;
			for (long[] record : records) {
				if (matches(subj, record[0]) && matches(pred, record[1]) && matches(obj, record[2])
						&& matches(context, record[3])) {
					count++;
				}
			}
			return count;
		}

		@Override
		public boolean has(long subj, long pred, long obj, long context) {
			directHasCalls++;
			for (long[] record : records) {
				if (matches(subj, record[0]) && matches(pred, record[1]) && matches(obj, record[2])
						&& matches(context, record[3])) {
					return true;
				}
			}
			return false;
		}

		@Override
		public double estimate(long subj, long pred, long obj, long context) {
			return count(subj, pred, obj, context);
		}

		@Override
		public boolean hasStatementsInSource() {
			return records.length != 0;
		}

		private static boolean matches(long requested, long actual) {
			return requested == UNKNOWN_ID || requested == actual;
		}
	}
